sp_widget.client_script:
api.controller = function($scope) {
    var c = this;
	c.estimativeTime = null;
	c.requesting = false;

	c.scenarioLabel = (scenario) => {
		const {hours, minutes} = scenario;
		let msg = '';
		if (hours > 0)
			msg = hours + (hours == 1 ? ' ${Hour}' : ' ${Hour}');
		if (hours > 0 && minutes > 0)
			msg += ' ${and}';
		if (minutes > 0)
			msg = msg + ' ' + minutes + ' ${minutes}';
		return msg;
	};

	c.handleRadioChange = (e) => {
		if (!e.target.checked) return;
		const key = e.target.dataset.key;
		let keys = ['scenario1', 'scenario2', 'scenario3'];
		for (let k of keys) {
			if (k != key && $scope[k]) {
				$scope[k].checked = false;
			}
		}
		c.estimativeTime = e.target.value;

		// $scope.data.estimateHour = c.estimativeTime/(60 * 60 * 1000);
	};

    $scope.cbTerms = {
        checked: false,
    };
	$scope.banner = {
		type: $scope.data.supportPlans.length === 0 ? 'alert' : 'info',
		bodyText:  $scope.data.bannerContent,
		dismissible: false,
	};

	$scope.scenarioGroup = {
		value: null,
	};
	if ($scope.data.scenario1) {
		$scope.scenario1 = {
			checked: false,
			value: $scope.data.scenario1.time,
			labelText: c.scenarioLabel($scope.data.scenario1),
			captionText: $scope.data.scenario1.description,
			events: {
				change: c.handleRadioChange
			}
		};
	}
	if ($scope.data.scenario2) {
		$scope.scenario2 = {
			checked: false,
			value: $scope.data.scenario2.time,
			labelText: c.scenarioLabel($scope.data.scenario2),
			captionText: $scope.data.scenario2.description,
			events: {
				change: c.handleRadioChange
			}
		};
	}
	if ($scope.data.scenario3) {
		$scope.scenario3 = {
			checked: false,
			value: $scope.data.scenario3.time,
			labelText: c.scenarioLabel($scope.data.scenario3),
			captionText: $scope.data.scenario3.description,
			events: {
				change: c.handleRadioChange
			}
		};
	}

	c.rejectDisabled = () => {
		return c.requesting || (!$scope.data.premierSupportPermission && !$scope.data.isMasterAdmin);
	};

    c.handleReject = () => {
		if (!c.hasPermission()) return;
		c.requesting = true;
		$scope.server.get({action: 'reject', caseId: $scope.data.caseId}).then(function() {			
			$scope.data.awaitingCustomerApproval = false;
			c.requesting = false;
			$scope.$emit('evt-case-estimation-rejected', {});
		});
	};

	c.approveDisabled = () => {
		let termsChecked = $scope.cbTerms.checked;
		if ($scope.data.scenario1 || $scope.data.scenario2 || $scope.data.scenario3) {
			return !termsChecked || !c.estimativeTime || (!$scope.data.premierSupportPermission && !$scope.data.isMasterAdmin);
		}
		return c.requesting || !termsChecked || (!$scope.data.premierSupportPermission && !$scope.data.isMasterAdmin);
	};

	c.handleApprove = () => {
		if (!c.hasPermission()) return;
		let payload = {
			action: 'approve', 
			caseId: $scope.data.caseId
		};
		if (c.estimativeTime) {
			payload.estimativeTime = c.estimativeTime;
		}
		c.requesting = true;
		$scope.server.get(payload).then(function() {			
			$scope.data.awaitingCustomerApproval = false;
			c.requesting = false;
			$scope.$emit('evt-case-estimation-rejected', {});
		});
	};

	c.totalCharges = () => {
		if ($scope.data.currentHours >= $scope.data.estimateHour) {
			return 0;
		}
		return $scope.data.pricePerHour * ($scope.data.estimateHour - $scope.data.currentHours);
	};

	c.hasPermission = () => {
		return $scope.data.premierSupportPermission || $scope.data.isMasterAdmin;
	};
};

sp_widget.script:
(function() {
    data.caseId = options.caseId;
    data.cmdbCi = null;
    data.note = '';
    data.pricePerHour = 999999999;
    data.priceUnit = '';
	data.totalNRC = 0;
    data.currentHours = 0;
    data.scenario1 = null;
    data.scenario2 = null;
    data.scenario3 = null;

    var siPortalCSM = new EQIX_Portal_CSM();
    var siCustomerPermission = new EQIX_Customer_Permissions();
    var siPremierSupport = new EQIX_GSD_PremierSupport();
    var account = siCustomerPermission.getActiveAccountSysId();
	var source = 'EQIX POE Pricing - Awaiting Customer Approval';

    var caseTypes = gs.getProperty('EQIX_Case_Associate_Types') || '';
    caseTypes = caseTypes.split(',');
    data.caseTypes = caseTypes;

    data.termsAndConditions = gs.getMessage('MS Premier Support terms and conditions');
    data.premierSupportPermission = siCustomerPermission.hasPermission('support_hours_approval', 'ticket', account);
	data.isMasterAdmin = siCustomerPermission.hasPermission('master_admin');

    if (input) {
        optCopy(['caseId', 'estimativeTime']);

        if (input.action == 'approve') {
            postMessage(data.caseId, data.estimativeTime);
            var grApprove = new GlideRecord('sn_customerservice_case');
            if (grApprove.get(data.caseId)) {
                if (caseTypes.indexOf(grApprove.getValue('u_type')) > -1) {
                    // association
                    var estimatedHours = parseInt(input.estimativeTime);
                    if (isNaN(estimatedHours)) {
                        estimatedHours = 0;
                    }

                    grApprove.u_new_customer_approval_performed = true;

                    grApprove.u_estimated_hours = new GlideDuration(estimatedHours);
                }
				grApprove.state = '10'; // Open			
				//grApprove.assigned_to = '';
				grApprove.u_execution_approval = true;
				grApprove.update();
            }
        }

        if (input.action == 'reject') {
            var caseReject = new GlideRecord('sn_customerservice_case');
            if (caseReject.get(data.caseId)) {
                caseReject.state = '35'; // Not approved			
                caseReject.update();
            }
        }

		return;
    }


    var theCase = new GlideRecord('sn_customerservice_case');
    if (!theCase.get(options.caseId)) {
        return;
    }
    data.caseId = options.caseId;
    data.cmdbCi = theCase.getValue('cmdb_ci');
    data.supportPlans = siPremierSupport.getSupportPlans(account, data.cmdbCi);
    data.awaitingCustomerApproval = theCase.state == 32;
	if (!data.awaitingCustomerApproval) return;
	// gs.addInfoMessage('data.supportPlans: ' + data.supportPlans.length);
    if (data.supportPlans.length === 0) {
        data.note = gs.getMessage('Note : This service will incur Non-Recurring Charges. The amount stated is an estimate and may vary from the final price.');
        data.bannerContent = gs.getMessage('You currently do not have an MS Premier Support Plan for the selected service.');
    } else {
        data.note = gs.getMessage('Note : The amount stated for Non Recurring Charges is an estimate and may vary from the final price.');
        data.bannerContent = gs.getMessage('Service Estimate is not considered for ongoing cases');
        data.currentHours = parseFloat(data.supportPlans[0].u_available_hours);
    }
	var gdtEstimation = theCase.getValue('u_estimated_hours');
	var timeComponents = gdtEstimation.toString().split(' ')[1];
	// timeComponents = '01:30:00';
	var hours = +timeComponents.split(":")[0];
	var minutes = +timeComponents.split(":")[1];
	data.estimateHour = hours + (minutes/60);
	data.estimateHourLabel = getDisplayTime(hours, minutes);


	var balanceHours = Math.floor(data.currentHours);
	var balanceMinutes = (data.currentHours - Math.floor(data.currentHours))*60;
	data.balanceLabel = getDisplayTime(balanceHours, balanceMinutes);
	var ibx = theCase.cmdb_ci.location.name.toString();
	if (data.estimateHour > data.currentHours) {
		var time = data.estimateHour - data.currentHours;
		var prices = siPortalCSM.getGenericPremierPrice(account, ibx, time, source);
		if (prices.length > 0) {
			data.priceUnit = prices[0];
			data.pricePerHour = prices[1];
			data.totalNRC = prices[2];
		} else {
			// pass through
		}

		var delta = data.estimateHour - data.currentHours;
		var chargeableHours = Math.floor(delta);
		var chargeableMinutes = (delta - Math.floor(delta))*60;
		data.chargeableHoursLabel = getDisplayTime(chargeableHours, chargeableMinutes);
	} else {
		var unitPrices = siPortalCSM.getGenericPremierPrice(account, ibx, 1, source);
		if (unitPrices.length > 0) {
			data.pricePerHour = unitPrices[1];
			data.priceUnit = unitPrices[0];
		}
		data.chargeableHoursLabel = getDisplayTime(0, 0);
	}

    if (caseTypes.indexOf(theCase.getValue('u_type')) > -1) {
        // If type is association
        data.scenarios = getScenarios();
    }
    function getScenarios() {
        var grTask = new GlideRecord('sn_customerservice_case_task');
        var scenarios = [];
        if (grTask.get('u_case', data.caseId)) {
            var scenario = {
                time: grTask.u_scenario_first.getGlideObject().getNumericValue(),
                hours: getHour(grTask.u_scenario_first.getGlideObject().getNumericValue()),
                minutes: getMinutes(grTask.u_scenario_first.getGlideObject().getNumericValue()),
                description: grTask.getDisplayValue('u_scenario_first_description') + ""
            };
            if (scenario.hours > 0 || scenario.minutes > 0) {
                data.scenario1 = scenario;
            }

            scenario = {
                time: grTask.u_scenario_second.getGlideObject().getNumericValue(),
                hours: getHour(grTask.u_scenario_second.getGlideObject().getNumericValue()),
                minutes: getMinutes(grTask.u_scenario_second.getGlideObject().getNumericValue()),
                description: grTask.getValue('u_scenario_second_description')
            };
            if (scenario.hours > 0 || scenario.minutes > 0) {
                data.scenario2 = scenario;
            }

            scenario = {
                time: grTask.u_scenario_third.getGlideObject().getNumericValue(),
                hours: getHour(grTask.u_scenario_third.getGlideObject().getNumericValue()),
                minutes: getMinutes(grTask.u_scenario_third.getGlideObject().getNumericValue()),
                description: grTask.getValue('u_scenario_third_description')
            };
            if (scenario.hours > 0 || scenario.minutes > 0) {
                data.scenario3 = scenario;
            }
        }
        return scenarios;
    }

    function postMessage(caseId, estimativeTime) {
        var grApprove = new GlideRecord('sn_customerservice_case');
        if (grApprove.get(caseId)) {
            if (caseTypes.indexOf(grApprove.getValue('u_type')) > -1) {
                // If type is association

				var msg = _buildMessage(estimativeTime);
				grApprove.comments = msg;

                var grSCCT = new GlideRecord('sn_customerservice_case_task');
                grSCCT.addQuery('u_case', caseId);
                grSCCT.query();
                while (grSCCT.next()) {
                    grSCCT.comments = msg;
                    grSCCT.update();
                }
            } else {
                // Regular type
				var estimateDuration = new GlideDateTime(grApprove.u_estimated_hours).getNumericValue();
                var msg = gs.getMessage('hour(s) effort estimate approved');
                grApprove.comments = estimateDuration / (3600 * 1000) + ' ' + msg;
            }
        }
        grApprove.update();
    }

    function _buildMessage(time) {
        if (!time)
            time = 0;

        var hours = parseInt(getHour(time));
        var minutes = parseInt(getMinutes(time));

        var msg = "";
        if (!isNaN(hours) && hours > 0) {
            msg += hours + gs.getMessage(" hour") + "(s)";
        }

        if (!isNaN(minutes) && minutes > 0) {
            if (msg.length > 0)
                msg += gs.getMessage(" and ");
            msg += minutes + gs.getMessage(" minute") + "(s)";
        }
        msg += gs.getMessage(' effort estimate approved');
        msg = msg.toLowerCase();
        return msg;
    }

	function getDisplayTime(hours, minutes) {
		var arr = [];
		if (hours == 0 && minutes == 0) {
			return gs.getMessage('{0} hrs', 0);
		}
		if (hours > 0) {
			if (hours > 1) {
				arr.push(gs.getMessage('{0} hrs', [parseInt(hours).toString()]));
			} else {
				arr.push(gs.getMessage('{0} hr', [parseInt(hours).toString()]));
			}
		}
		if (minutes > 0) {
			if (minutes > 1) {
				arr.push(gs.getMessage('{0} mins', [parseInt(minutes).toString()]));
			} else {
				arr.push(gs.getMessage('{0} min', [parseInt(minutes).toString()]));
			}
		}

		return arr.join(' ');
	}

    function getHour(ms) {

        if (!ms) {
            return 0;
        }

        var hours = Math.floor((ms / (60 * 60 * 1000)));
        if (hours < 9) {
            hours = "0" + hours;
        }
        return String(hours);
    }

    // Return only minutes
    function getMinutes(ms) {

        if (!ms) {
            return 0;
        }

        var hours = (ms / (60 * 60 * 1000));
        var absoluteHours = Math.floor(hours);

        //Get remainder from hours and convert to minutes
        var minutes = (hours - absoluteHours) * 60;
        if (minutes < 9) {
            minutes = "0" + minutes;
        }
        return String(minutes);
    }

    function optCopy(names) {
        names.forEach(function(name) {
            data[name] = input[name] !== undefined ? input[name] : options[name];
        });
    }

})();
